def solve(age, heart_rate, hypertension, prior_mi, prior_stroke, renal_insufficiency, anemia, lvef_below_50, elevated_ctn, st_changes):
    # Step 1: age_score_calculation
    # Map patient's age to a predefined score based on clinical risk stratification tiers.
    if age < 40:
        age_score = 0
    elif age < 50:
        age_score = 9
    elif age < 60:
        age_score = 29
    elif age < 65:
        age_score = 41
    elif age < 70:
        age_score = 50
    elif age < 75:
        age_score = 58
    elif age < 80:
        age_score = 65
    else:
        age_score = 71
    yield {
        "step_name": "age_score_calculation",
        "step_description": "Calculate the score based on the patient's age group.",
        "step_result": age_score,
        "unit": None
    }

    # Step 2: heart_rate_score_calculation
    # Map patient's heart rate to a predefined score based on clinical risk stratification tiers.
    if heart_rate < 60:
        heart_rate_score = 0
    elif heart_rate < 70:
        heart_rate_score = 14
    elif heart_rate < 80:
        heart_rate_score = 18
    elif heart_rate < 90:
        heart_rate_score = 21
    elif heart_rate < 100:
        heart_rate_score = 24
    elif heart_rate <= 110:
        heart_rate_score = 30
    else:
        heart_rate_score = 36
    yield {
        "step_name": "heart_rate_score_calculation",
        "step_description": "Calculate the score based on the patient's heart rate.",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 3: binary_risk_factor_scores_calculation
    # Evaluate eight independent clinical risk factors, assign a fixed score to each if present, and sum them.
    binary_scores_sum = 0
    if hypertension:
        binary_scores_sum += 20
    if prior_mi:
        binary_scores_sum += 16
    if prior_stroke:
        binary_scores_sum += 16
    if renal_insufficiency:
        binary_scores_sum += 21
    if anemia:
        binary_scores_sum += 19
    if lvef_below_50:
        binary_scores_sum += 22
    if elevated_ctn:
        binary_scores_sum += 23
    if st_changes:
        binary_scores_sum += 13
    yield {
        "step_name": "binary_risk_factor_scores_calculation",
        "step_description": "Calculate scores for the eight binary risk factors and sum them up.",
        "step_result": binary_scores_sum,
        "unit": None
    }

    # Step 4: total_opt_cad_score_calculation
    # Sum all component scores to compute the final OPT-CAD score.
    total_opt_cad_score = age_score + heart_rate_score + binary_scores_sum
    return total_opt_cad_score
